1	interface QuoteItem {
2	  type: string;
3	  material?: string;
4	  enchantment?: number;
5	  cursed?: boolean;
6	}
7	
8	interface QuoteInput {
9	  customer: { yearsWithMHPCO: number };
10	  items: QuoteItem[];
11	  contractIndex?: number;
12	  firstInsurance?: boolean;
13	  followUp?: boolean;
14	}
15	
16	const PROCESSING_FEE = 5;
17	
18	const BASE_PREMIUMS: Record<string, number> = {
19	  sword: 100,
20	  amulet: 60,
21	  staff: 80,
22	  potion: 40,
23	  rune: 25,
24	  moonstone: 25,
25	};
26	
27	const BLOCK_SIZE = 3;
28	const BLOCK_PREMIUM = 60;
29	
30	const CURSE_SURCHARGE_RATE = 0.5;
31	
32	const HIGH_ENCHANTMENT_THRESHOLD = 5;
33	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
34	
35	function countByType(items: QuoteItem[]): Map<string, number> {
36	  const counts = new Map<string, number>();
37	  for (const item of items) {
38	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
39	  }
40	  return counts;
41	}
42	
43	function priceGroup(type: string, count: number): number {
44	  return count === BLOCK_SIZE ? BLOCK_PREMIUM : BASE_PREMIUMS[type] * count;
45	}
46	
47	function surchargeFor(
48	  items: QuoteItem[],
49	  applies: (item: QuoteItem) => boolean,
50	  rate: number,
51	): number {
52	  let surcharge = 0;
53	  for (const item of items) {
54	    if (applies(item)) {
55	      surcharge += BASE_PREMIUMS[item.type] * rate;
56	    }
57	  }
58	  return surcharge;
59	}
60	
61	function curseSurchargeFor(items: QuoteItem[]): number {
62	  return surchargeFor(items, (item) => item.cursed === true, CURSE_SURCHARGE_RATE);
63	}
64	
65	function highEnchantmentSurchargeFor(items: QuoteItem[]): number {
66	  return surchargeFor(
67	    items,
68	    (item) => (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD,
69	    HIGH_ENCHANTMENT_SURCHARGE_RATE,
70	  );
71	}
72	
73	function policyBasePremiumFor(items: QuoteItem[]): number {
74	  const countsByType = countByType(items);
75	
76	  let basePremium = 0;
77	  for (const [type, count] of countsByType) {
78	    basePremium += priceGroup(type, count);
79	  }
80	  return basePremium;
81	}
82	
83	function itemSurchargesFor(items: QuoteItem[]): number {
84	  return curseSurchargeFor(items) + highEnchantmentSurchargeFor(items);
85	}
86	
87	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
88	
89	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
90	
91	const LOYALTY_YEARS_THRESHOLD = 2;
92	const LOYALTY_DISCOUNT_RATE = 0.2;
93	
94	function applyLoyaltyDiscount(basePremium: number, yearsWithMHPCO: number): number {
95	  if (yearsWithMHPCO < LOYALTY_YEARS_THRESHOLD) {
96	    return basePremium;
97	  }
98	  return basePremium * (1 - LOYALTY_DISCOUNT_RATE);
99	}
100	
101	function gatedPolicyBaseModifier(active: boolean | undefined, policyBasePremium: number, rate: number): number {
102	  return active ? policyBasePremium * rate : 0;
103	}
104	
105	export function quote(input: QuoteInput): number {
106	  const policyBasePremium = policyBasePremiumFor(input.items);
107	  const premiumWithSurcharges = policyBasePremium + itemSurchargesFor(input.items);
108	  const afterLoyalty = applyLoyaltyDiscount(premiumWithSurcharges, input.customer.yearsWithMHPCO);
109	  const firstInsuranceSurcharge = gatedPolicyBaseModifier(input.firstInsurance, policyBasePremium, FIRST_INSURANCE_SURCHARGE_RATE);
110	  const followUpDiscount = gatedPolicyBaseModifier(input.followUp, policyBasePremium, FOLLOW_UP_DISCOUNT_RATE);
111	  return Math.ceil(afterLoyalty + firstInsuranceSurcharge - followUpDiscount + PROCESSING_FEE);
112	}
113	
114	export function claim(input: unknown): number {
115	  return undefined as unknown as number;
116	}
